```cpp
// Define the pins for the IR sensors and motor control
const int leftSensorPin = A0;
const int centerSensorPin = A1;
const int rightSensorPin = A2;
const int leftMotorPin = 9;
const int rightMotorPin = 10;

// Define the PID constants
const float Kp = 1.2;
const float Ki = 3.0;
const float Kd = 0.2;

// Define the desired position on the line (centered)
const int desiredPosition = 500;

// Define variables for PID calculations
float proportional = 0;
float integral = 0;
float derivative = 0;
float lastError = 0;

void setup() {
  // Initialize the motor control pins as output
  pinMode(leftMotorPin, OUTPUT);
  pinMode(rightMotorPin, OUTPUT);

  // Initialize serial communication for debugging
  Serial.begin(9600);
}

void loop() {
  // Read sensor values
  int leftSensorValue = analogRead(leftSensorPin);
  int centerSensorValue = analogRead(centerSensorPin);
  int rightSensorValue = analogRead(rightSensorPin);

  // Calculate error
  float error = (centerSensorValue - desiredPosition);

  // Calculate PID terms
  proportional = error;
  integral += error;
  derivative = error - lastError;

  // Calculate PID output
  float pidOutput = (Kp * proportional) + (Ki * integral) + (Kd * derivative);

  // Update motor speeds
  int leftMotorSpeed = 255 - pidOutput;
  int rightMotorSpeed = 255 + pidOutput;

  // Set motor speeds with appropriate direction
  if (leftMotorSpeed > 0) {
    digitalWrite(leftMotorPin, HIGH);
    analogWrite(leftMotorPin+1, leftMotorSpeed);
  } else {
    digitalWrite(leftMotorPin, LOW);
    analogWrite(leftMotorPin+1, -leftMotorSpeed);
  }

  if (rightMotorSpeed > 0) {
    digitalWrite(rightMotorPin, HIGH);
    analogWrite(rightMotorPin+1, rightMotorSpeed);
  } else {
    digitalWrite(rightMotorPin, LOW);
    analogWrite(rightMotorPin+1, -rightMotorSpeed);
  }

  // Print debug information
  Serial.print("Left: ");
  Serial.print(leftSensorValue);
  Serial.print("\tCenter: ");
  Serial.print(centerSensorValue);
  Serial.print("\tRight: ");
  Serial.print(rightSensorValue);
  Serial.print("\tPID: ");
  Serial.print(pidOutput);
  Serial.print("\tLeft speed: ");
  Serial.print(leftMotorSpeed);
  Serial.print("\tRight speed: ");
  Serial.println(rightMotorSpeed);

  // Update last error
  lastError = error;
}
```

In this code, the infrared sensors are connected to analog input pins A0, A1, and A2 on the Arduino board. The motor control pins are connected to digital pins 9 and 10. The PID constants Kp, Ki, and Kd can be adjusted to fine-tune the line following behavior. The desired position on the line is set as `desiredPosition` (you may need to adjust this value based on your specific setup).

The code reads the sensor values, calculates the error with respect to the desired position, calculates the PID output, and adjusts the motor speeds accordingly. Debug information is printed via the serial monitor for monitoring the sensor values, PID output, and motor speeds.

Make sure you have the necessary motor control and sensor libraries included in your Arduino environment. Additionally, ensure the connections of the motors and sensors to the Arduino board are set correctly based on your specific hardware setup.

